describe("pipeline atoms — initial state", () => {
  let registry: Registry.Registry

  beforeEach(() => {
    registry = makeRegistry()
  })

  it("pipelineStepsAtom initial value has 6 steps", () => {
    const steps = registry.get(pipelineStepsAtom)
