import { Schema } from "effect"

// Branded IDs
export const TxHash = Schema.String.pipe(Schema.brand("@Falcon/TxHash"))
export type TxHash = Schema.Schema.Type<typeof TxHash>

export const ContractAddress = Schema.String.pipe(Schema.brand("@Falcon/ContractAddress"))
export type ContractAddress = Schema.Schema.Type<typeof ContractAddress>

// Domain types
export interface FalconKeypair {
  readonly secretKey: Uint8Array
  readonly verifyingKey: Uint8Array
  readonly publicKeyNtt: Int32Array // h polynomial, 512 coefficients
}

export interface FalconSignatureResult {
  readonly signature: Uint8Array
  readonly salt: Uint8Array
}

export interface PackedPublicKey {
  readonly slots: ReadonlyArray<string> // 29 hex strings (felt252)
}

export type VerificationStep =
  | { step: "idle" }
  | { step: "generating-keypair" }
  | { step: "signing" }
  | { step: "creating-hint" }
  | { step: "packing" }
  | { step: "verifying"; substep: string }
  | { step: "complete"; valid: boolean; durationMs: number }
  | { step: "error"; message: string }

export interface PipelineStep {
  readonly id: string
  readonly name: string
  readonly description: string
  readonly input: string
  readonly output: string
  readonly stepCount: number
  readonly status: "pending" | "active" | "complete"
}

/**
 * VP-004: Tests for the atoms/index.ts barrel re-export.
 *
 * These tests verify:
 * - All atoms from falcon.ts, starknet.ts, pipeline.ts are accessible via the barrel
 * - wasmStatusAtom has keepAlive: true (required by PRD)
 * - Types and constants are re-exported correctly
 *
 * RED: Will fail until atoms/index.ts is created.
 */

import { describe, it, expect } from "bun:test"
import { Option } from "effect"
import { Registry } from "@effect-atom/atom"

// Import everything via the barrel — this is the contract being tested
import {
  // falcon.ts exports
  wasmStatusAtom,
  keypairAtom,
  signatureAtom,
  verificationStepAtom,
  messageAtom,
  // starknet.ts exports
  deployStepAtom,
  deployedAddressAtom,
  deployTxHashAtom,
  // pipeline.ts exports
  pipelineStepsAtom,
  pipelineActiveStepAtom,
  pipelinePlayingAtom,
  INITIAL_PIPELINE_STEPS,
} from "../atoms"

// ---------------------------------------------------------------------------
// wasmStatusAtom — keepAlive contract
// ---------------------------------------------------------------------------

describe("wasmStatusAtom via barrel export", () => {
  it("is exported from the barrel", () => {
    expect(wasmStatusAtom).toBeDefined()
  })

  it("keepAlive is true (required: stays alive across component unmounts)", () => {
    // Atom.keepAlive sets the keepAlive flag on the atom descriptor.
    // This is critical for the WASM status to persist across navigation.
    expect(wasmStatusAtom.keepAlive).toBe(true)
  })

  it("initial value is 'loading'", () => {
    const registry = Registry.make()
    expect(registry.get(wasmStatusAtom)).toBe("loading")
  })
})

// ---------------------------------------------------------------------------
// keypairAtom via barrel
// ---------------------------------------------------------------------------

describe("keypairAtom via barrel export", () => {
  it("is exported from the barrel", () => {
    expect(keypairAtom).toBeDefined()
  })

  it("initial value is Option.none()", () => {
    const registry = Registry.make()
    expect(Option.isNone(registry.get(keypairAtom))).toBe(true)
  })
})

// ---------------------------------------------------------------------------
// signatureAtom via barrel
// ---------------------------------------------------------------------------

describe("signatureAtom via barrel export", () => {
  it("is exported from the barrel", () => {
    expect(signatureAtom).toBeDefined()
  })

  it("initial value is Option.none()", () => {
    const registry = Registry.make()
    expect(Option.isNone(registry.get(signatureAtom))).toBe(true)
  })
})

// ---------------------------------------------------------------------------
// verificationStepAtom via barrel
// ---------------------------------------------------------------------------

describe("verificationStepAtom via barrel export", () => {
  it("is exported from the barrel", () => {
    expect(verificationStepAtom).toBeDefined()
  })

  it("initial value step is 'idle'", () => {
    const registry = Registry.make()
    expect(registry.get(verificationStepAtom).step).toBe("idle")
  })
})

// ---------------------------------------------------------------------------
// messageAtom via barrel
// ---------------------------------------------------------------------------

describe("messageAtom via barrel export", () => {
  it("is exported from the barrel", () => {
    expect(messageAtom).toBeDefined()
  })

  it("initial value is empty string", () => {
    const registry = Registry.make()
    expect(registry.get(messageAtom)).toBe("")
  })
})

// ---------------------------------------------------------------------------
// starknet atoms via barrel
// ---------------------------------------------------------------------------

describe("starknet atoms via barrel export", () => {
  it("deployStepAtom is exported", () => {
    expect(deployStepAtom).toBeDefined()
  })

  it("deployStepAtom initial step is 'idle'", () => {
    const registry = Registry.make()
    expect(registry.get(deployStepAtom).step).toBe("idle")
  })

  it("deployedAddressAtom is exported and starts as Option.none()", () => {
    expect(deployedAddressAtom).toBeDefined()
    const registry = Registry.make()
    expect(Option.isNone(registry.get(deployedAddressAtom))).toBe(true)
  })

  it("deployTxHashAtom is exported and starts as Option.none()", () => {
    expect(deployTxHashAtom).toBeDefined()
    const registry = Registry.make()
    expect(Option.isNone(registry.get(deployTxHashAtom))).toBe(true)
  })
})

// ---------------------------------------------------------------------------
// pipeline atoms via barrel
// ---------------------------------------------------------------------------

describe("pipeline atoms via barrel export", () => {
  it("pipelineStepsAtom is exported", () => {
    expect(pipelineStepsAtom).toBeDefined()
  })

  it("pipelineActiveStepAtom initial value is -1", () => {
    const registry = Registry.make()
    expect(registry.get(pipelineActiveStepAtom)).toBe(-1)
  })

  it("pipelinePlayingAtom initial value is false", () => {
    const registry = Registry.make()
    expect(registry.get(pipelinePlayingAtom)).toBe(false)
  })

  it("INITIAL_PIPELINE_STEPS is exported and has 6 entries", () => {
    expect(INITIAL_PIPELINE_STEPS).toHaveLength(6)
  })
})

// ---------------------------------------------------------------------------
// No name conflicts: all atoms are distinct objects
// ---------------------------------------------------------------------------

describe("barrel export integrity — no name collisions", () => {
  it("all exported atoms are distinct objects", () => {
    const atoms = [
      wasmStatusAtom,
      keypairAtom,
      signatureAtom,
      verificationStepAtom,
      messageAtom,
      deployStepAtom,
      deployedAddressAtom,
      deployTxHashAtom,
      pipelineStepsAtom,
      pipelineActiveStepAtom,
      pipelinePlayingAtom,
    ]
    // All atoms should be distinct references
    const uniqueAtoms = new Set(atoms)
    expect(uniqueAtoms.size).toBe(atoms.length)
  })
})

