  })

  it("transitions from loading → error", () => {
    const registry = makeRegistry()
    registry.set(wasmStatusAtom, "error")
    expect(registry.get(wasmStatusAtom)).toBe("error")
  })

  it("transitions back to loading from ready (reset)", () => {
